from collections import deque

def levelOrder(root):
    if root is None:
        return

    queue = deque([root])

    while queue:
        node = queue.popleft()
        print(node.data, end=' ')

        if node.left:
            queue.append(node.left)
        if node.right:
            queue.append(node.right)

# Example output for tree: 1 2 3 4 5 6 7
# Output: 1 2 3 4 5 6 7
